<span class="line"><span style="--shiki-light:#E36209;--shiki-dark:#FFAB70;">        buf</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">[i] </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> (u8)i;</span></span>
